import type { SubwayStation } from './types';
import { SUBWAY_COLOR_SCALE, SELECTED_COLOR, LAYER_COLORS } from './types';

// ── UI helpers ──────────────────────────────────────────

const statusEl = document.getElementById('loading-status')!;
const overlayEl = document.getElementById('loading-overlay')!;
const infoPanel = document.getElementById('info-panel')!;
const infoTitle = document.getElementById('info-title')!;
const infoBody = document.getElementById('info-body')!;

function setStatus(msg: string) {
  statusEl.textContent = msg;
  console.log(`[Status] ${msg}`);
}

function hideOverlay() {
  overlayEl.classList.add('hidden');
}

function showInfo(title: string, html: string) {
  infoTitle.textContent = title;
  infoBody.innerHTML = html;
  infoPanel.classList.add('visible');
}

// ── Subway data ─────────────────────────────────────────

async function loadSubwayStations(): Promise<SubwayStation[]> {
  console.log('[Data] Loading subway stations CSV…');
  const res = await fetch('/subway_manhattan_clean.csv');
  const text = await res.text();
  const parsed = Papa.parse<SubwayStation>(text, { header: true, dynamicTyping: true, skipEmptyLines: true });
  console.log(`[Data] Parsed ${parsed.data.length} subway stations`);
  return parsed.data;
}

// ── Map setup ───────────────────────────────────────────

function createMap(): maplibregl.Map {
  console.log('[Map] Initializing MapLibre GL…');
  const map = new maplibregl.Map({
    container: 'map',
    style: {
      version: 8,
      sources: {
        'osm-tiles': {
          type: 'raster',
          tiles: ['https://tile.openstreetmap.org/{z}/{x}/{y}.png'],
          tileSize: 256,
          attribution: '&copy; <a href="https://www.openstreetmap.org/copyright">OpenStreetMap</a> contributors',
        },
      },
      layers: [
        {
          id: 'osm-base',
          type: 'raster',
          source: 'osm-tiles',
          paint: { 'raster-opacity': 0.35 },
        },
      ],
    },
    center: [-73.9712, 40.7831],
    zoom: 13,
    pitch: 50,
    bearing: -17.6,
    antialias: true,
  });

  map.addControl(new maplibregl.NavigationControl(), 'top-left');
  return map;
}

// ── Color expressions ───────────────────────────────────

function buildSubwayColorExpr(): maplibregl.ExpressionSpecification {
  // step expression over subwayCount property
  const steps: (string | number)[] = [];
  for (let i = 0; i < SUBWAY_COLOR_SCALE.length; i++) {
    const [threshold, color] = SUBWAY_COLOR_SCALE[i];
    if (i === 0) {
      // default/fallback color (for values below first threshold)
      steps.push(color);
    } else {
      steps.push(threshold, color);
    }
  }
  return [
    'case',
    ['boolean', ['feature-state', 'selected'], false],
    SELECTED_COLOR,
    ['step', ['get', 'subwayCount'], ...steps],
  ] as maplibregl.ExpressionSpecification;
}

function selectedFillColor(baseColor: string): maplibregl.ExpressionSpecification {
  return [
    'case',
    ['boolean', ['feature-state', 'selected'], false],
    SELECTED_COLOR,
    baseColor,
  ] as maplibregl.ExpressionSpecification;
}

function selectedLineColor(baseColor: string): maplibregl.ExpressionSpecification {
  return [
    'case',
    ['boolean', ['feature-state', 'selected'], false],
    SELECTED_COLOR,
    baseColor,
  ] as maplibregl.ExpressionSpecification;
}

