  map.addSource(id, { type: 'geojson', data, promoteId: 'id' });
  map.addLayer({
    id,
    type: 'line',
    source: id,
    paint: {
      'line-color': selectedLineColor(color),
      'line-width': width,
      'line-opacity': 0.7,
